        # Check for patterns like "drop row i if row i+1 has property X"
        for pattern_name, pattern_func in [
            ("next_row_has_duplicate", self._check_next_duplicate),
            ("prev_row_has_duplicate", self._check_prev_duplicate),
            ("drop_first_in_segment", self._check_drop_first_in_segment),
            ("drop_last_in_segment", self._check_drop_last_in_segment),
            ("drop_duplicates_but_keep_first", self._check_keep_first_only),
            ("drop_equal_to_next", self._check_drop_equal_to_next),
        ]:
            result = pattern_func(kept_indices, dropped_indices)
            if result:
                result["pattern"] = pattern_name
                return result

        return None

    def _check_next_duplicate(self, kept_indices: Set[int], dropped_indices: List[int]) -> Optional[Dict]:
        """Check if pattern: drop row if next row has status='duplicate'."""
        if not self.input_rows or "status" not in self.input_rows[0]:
            return None

        # Check if dropped rows correlate with next row having duplicate status
        for i in dropped_indices:
            if i + 1 < len(self.input_rows) and self.input_rows[i + 1].get("status") == "duplicate":
                if i not in kept_indices:  # i is actually dropped
                    # Check if this matches consistently
                    matches = 0
                    total = 0
                    for idx in range(len(self.input_rows) - 1):
                        if self.input_rows[idx + 1].get("status") == "duplicate":
                            total += 1
                            if idx not in kept_indices:
                                matches += 1
                    if total > 0 and matches >= total * 0.8:  # 80% match threshold
                        return {
                            "condition": "next_row",
                            "field": "status",
                            "value": "duplicate",
                            "drop_next": True
                        }
        return None

    def _check_keep_first_only(self, kept_indices: Set[int], dropped_indices: List[int]) -> Optional[Dict]:
        """Check if pattern: keep only first of consecutive duplicate values."""
        if len(self.input_rows) < 2:
            return None

        # Check if dropped rows are non-first duplicates
        first_col = self._input_column_names[0] if self._input_column_names else list(self.input_rows[0].keys())[0]
        consecutive_groups = []
        current_group = []

        for i, row in enumerate(self.input_rows):
            if current_group and row.get(first_col) == self.input_rows[current_group[0]].get(first_col):
                current_group.append(i)
            else:
                if len(current_group) > 1:
                    consecutive_groups.append(current_group)
                current_group = [i]

        if current_group and len(current_group) > 1:
            consecutive_groups.append(current_group)

        for group in consecutive_groups:
            first = group[0]
            rest = group[1:]
            if first in kept_indices and all(idx not in kept_indices for idx in rest):
                return {
                    "pattern": "keep_first_of_duplicates",
                    "field": first_col
                }

        return None

    def _check_drop_first_in_segment(self, kept_indices: Set[int], dropped_indices: List[int]) -> Optional[Dict]:
        """Check if pattern: drop first row of each segment."""
        # Check for segment_id pattern
        if not self.input_rows:
            return None

        output_cols = set()
        for row in self.output_rows:
            output_cols.update(row.keys())

        if "segment_id" in output_cols or "phase" in output_cols:
            # Check if first rows of segments are dropped
            # This would be detected by segment inference
            return {"pattern": "drop_first_in_segment"}

        return None

    def _check_drop_equal_to_next(self, kept_indices: Set[int], dropped_indices: List[int]) -> Optional[Dict]:
        """Check if pattern: drop row if equal to next row in column."""
        first_col = self._input_column_names[0] if self._input_column_names else None
        if not first_col:
            return None

        # Check pattern
        match_count = 0
        total = 0
        for i in range(len(self.input_rows) - 1):
            if self.input_rows[i].get(first_col) == self.input_rows[i+1].get(first_col):
                total += 1
                if i in dropped_indices:
                    match_count += 1

        if total > 0 and match_count >= total * 0.7:
            return {
                "pattern": "drop_equal_to_next",
                "field": first_col
            }

        return None

    def _infer_column_filter(self, kept_rows: List[Dict], dropped_rows: List[Dict]) -> Optional[Dict]:
        """Infer column-based filter."""
        if not kept_rows or not dropped_rows:
            return None

        col_filters = []

        for col in self._input_column_names:
            kept_vals = [r.get(col) for r in kept_rows if col in r]
            dropped_vals = [r.get(col) for r in dropped_rows if col in r]

            if not kept_vals or not dropped_vals:
                continue

            # Check for equality filter
            if len(set(kept_vals)) == 1:
                val = kept_vals[0]
                if not any(dv == val for dv in dropped_vals if dv is not None):
                    col_filters.append(("eq", col, val))

            # Check for inequality filter
            if len(set(dropped_vals)) == 1:
                val = dropped_vals[0]
                if not any(kv == val for kv in kept_vals if kv is not None):
                    col_filters.append(("ne", col, val))

            # Check for > filters (numeric)
            if all(isinstance(v, (int, float)) and v is not None for v in kept_vals + dropped_vals):
                max_dropped = max(v for v in dropped_vals if v is not None)
                min_kept = min(v for v in kept_vals if v is not None)

                if min_kept > max_dropped:
                    col_filters.append(("gt", col, max_dropped))

        if col_filters:
            return {"filters": col_filters}
        return None

    def _infer_column_transforms(self):
        """Infer transformations for each output column."""
        kept_input_rows = [r for kept, r in zip([p[1] for p in self.filter_predicates], self.input_rows) if kept]

        for out_col in self.output_columns:
            if out_col not in self.output_rows[0] or (out_col in self.input_rows[0] and out_col not in [t[1][0] for t in self.filter_predicates if not t[1]]):
                # Check if this output column might be a stateful transform
                transform_info = self._infer_stateful_transform(out_col, kept_input_rows)
                if transform_info:
                    self._stateful_transforms[out_col] = transform_info
                else:
                    # Fall back to simple transform inference
                    simple_info = self._infer_simple_transform(out_col, kept_input_rows)
                    self.column_transforms[out_col] = simple_info
            else:
                # Column exists in input, check if it's transformed
                transform_info = self._infer_stateful_transform(out_col, kept_input_rows)
                if transform_info:
                    self._stateful_transforms[out_col] = transform_info
                else:
                    simple_info = self._infer_simple_transform(out_col, kept_input_rows)
                    self.column_transforms[out_col] = simple_info

    def _infer_simple_transform(self, out_col: str, kept_input_rows: List[Dict]) -> Dict:
        """Infer simple (non-stateful) transform for a column."""
        if not kept_input_rows:
            return {"type": "constant", "value": None}

        # Check for constant
        first_val = kept_input_rows[0].get(out_col)
        if all(r.get(out_col) == first_val for r in kept_input_rows[1:] if out_col in r):
            return {"type": "constant", "value": first_val}

        # Check direct copy
        if out_col in self.input_rows[0]:
            return {"type": "copy", "source": out_col}

        # Check for numeric transform
        in_vals = [r.get(out_col) for r in kept_input_rows if out_col in r]
        out_vals = [r.get(out_col) for r in kept_input_rows if out_col in self.output_rows[0].keys()]

        if in_vals and all(isinstance(v, (int, float)) for v in in_vals if v is not None):
            # Check if it's a linear transform
            num_pairs = [(iv, ov) for iv, ov in zip(in_vals[:len(out_vals)], out_vals)
                         if isinstance(iv, (int, float)) and isinstance(ov, (int, float))]
            if len(num_pairs) >= 2:
                x1, y1 = num_pairs[0]
                x2, y2 = num_pairs[1]
                if x2 != x1:
                    a = (y2 - y1) / (x2 - x1)
                    b = y1 - a * x1
                    if all(abs(a * x + b - y) < 1e-6 for x, y in num_pairs):
                        return {"type": "numeric_transform", "op": "linear", "a": a, "b": b}

        return {"type": "copy", "source": out_col}  # Fallback to copy if source exists

    def _infer_stateful_transform(self, out_col: str, kept_input_rows: List[Dict]) -> Optional[Dict]:
        """Infer if a column represents a stateful transform."""
        if not kept_input_rows or out_col not in kept_input_rows[0]:
            return None

        # Get values from both input and output
        out_vals = [r.get(out_col) for r in kept_input_rows]
        input_vals = [r.get(self._get_corresponding_input(out_col, r)) for r in kept_input_rows]

        # Check for prefix sum
        prefix_sum_info = self._check_prefix_sum(in_vals, out_vals)
        if prefix_sum_info:
            return {"type": "stateful", "kind": "prefix_sum", "source": self._get_corresponding_input(out_col, kept_input_rows[0]), "details": prefix_sum_info}

        # Check for sliding window
        window_info = self._check_sliding_window(in_vals, out_vals)
        if window_info:
            return {"type": "stateful", "kind": "sliding_window", "source": self._get_corresponding_input(out_col, kept_input_rows[0]), "details": window_info}

        # Check for state machine (segment_id, phase, etc.)
        state_machine_info = self._check_state_machine(out_col, kept_input_rows)
        if state_machine_info:
            return {"type": "stateful", "kind": "state_machine", "source": state_machine_info.get("source", ""), "details": state_machine_info}

        return None

    def _get_corresponding_input(self, out_col: str, sample_row: Dict) -> str:
        """Find which input column corresponds to an output column."""
        for in_col in self._input_column_names:
            if in_col in sample_row and sample_row.get(in_col) is not None:
                return in_col
        for in_col in self.input_rows[0].keys():
            return in_col
        return "value"

    def _check_prefix_sum(self, in_vals: List, out_vals: List) -> Optional[Dict]:
        """Check if out_vals is cumulative sum/in of in_vals."""
        # Handle None/empty values
        filtered_pairs = [(iv, ov) for iv, ov in zip(in_vals, out_vals)
                         if isinstance(iv, (int, float)) and isinstance(ov, (int, float))]
        if len(filtered_pairs) < 2:
            return None

        # Check if out[i] = sum(in[0..i])
        running = 0
        for i, (iv, ov) in enumerate(filtered_pairs):
            running += iv
            if abs(ov - running) > 1e-6:
                # Check for different formula
                # Maybe out[i] = a * prefix_sum + b
                if i >= 1:
                    prefix = sum(v for v, _ in filtered_pairs[:i+1])
                    # This needs careful checking
                    pass
                return None

        return {"coeff_a": 1.0, "coeff_b": 0.0, "op": "sum"}

    def _check_sliding_window(self, in_vals: List, out_vals: List) -> Optional[Dict]:
        """Check if out_vals follows a sliding window pattern."""
        numeric_pairs = [(iv, ov) for iv, ov in zip(in_vals, out_vals)
                        if isinstance(iv, (int, float)) and isinstance(ov, (int, float))]
        if len(numeric_pairs) < 2:
            return None

        # Try different window sizes
        for window_size in range(1, min(65, len(numeric_pairs) + 1)):
            result = self._verify_window_pattern(numeric_pairs, window_size)
            if result:
                result["window_size"] = window_size
                return result

        return None

    def _verify_window_pattern(self, pairs: List[Tuple], window_size: int) -> Optional[Dict]:
        """Verify if values follow a window sum/avg pattern for given window size."""
        if len(pairs) < window_size:
            return None

        for i in range(window_size - 1, len(pairs)):
            window_vals = [p[0] for p in pairs[i-window_size+1:i+1]]
            expected_sum = sum(window_vals)
            expected_avg = expected_sum / window_size

            actual = pairs[i][1]

            if abs(actual - expected_sum) < 1e-6:
                return {"op": "sum"}
            if abs(actual - expected_avg) < 1e-6:
                return {"op": "avg"}

        return None

    def _check_state_machine(self, col: str, rows: List[Dict]) -> Optional[Dict]:
        """Check if column follows a state machine / sequence labeling pattern."""
        if col not in rows[0]:
            return None

        vals = [r.get(col) for r in rows]
        input_vals = [self._get_corresponding_input(col, r)]

        # Check for segment ID pattern
        if self._is_segment_id_pattern(vals):
            return {
                "kind": "segment_id",
                "source": self._find_trigger_column(rows, col)
            }

        # Check for phase flag pattern (boolean switches)
        if self._is_phase_flag_pattern(vals):
            return {
                "kind": "phase_flag",
                "source": self._find_trigger_column(rows, col)
            }

        return None

    def _is_segment_id_pattern(self, vals: List) -> bool:
        """Check if values form a segment ID pattern (increment on condition)."""
        if len(vals) < 2:
            return False

        # Segment IDs should be integers or strings representing segments
        try:
            int_vals = [int(v) if v is not None else -1 for v in vals]
        except (ValueError, TypeError):
            # Try to check if it's string pattern like "seg1", "seg2"
            return self._check_string_segment_pattern(vals)

        # Check for monotonic non-decreasing with increments of 0 or 1
        changes = 0
        for i in range(1, len(int_vals)):
            if int_vals[i] < int_vals[i-1]:
                return False  # Should not decrease
            if int_vals[i] > int_vals[i-1]:
                if int_vals[i] - int_vals[i-1] > 1:
                    return False  # Should increment by at most 1
                changes += 1

        # Should have some changes but not too many
        return changes > 0 and changes <= len(int_vals) // 2

    def _check_string_segment_pattern(self, vals: List) -> bool:
        """Check string segment pattern like 'seg1', 'seg2', etc."""
        if len(vals) < 2:
            return False

        try:
            nums = []
            for v in vals:
                if v is None:
                    return False
                # Extract number from string
                import re
                match = re.search(r'(\d+)', str(v))
                if match:
                    nums.append(int(match.group(1)))
                else:
                    return False

            return self._is_segment_id_pattern(nums)
        except:
            return False

    def _is_phase_flag_pattern(self, vals: List) -> bool:
        """Check if values form a phase/flag pattern (alternating or toggling)."""
        if len(vals) < 2:
            return False

        # Should be limited distinct values (usually 2-4)
        distinct = set(vals)
        if len(distinct) > 4:
            return False

        # Check if there's a pattern of staying constant then switching
        switch_count = 0
        for i in range(1, len(vals)):
            if vals[i] != vals[i-1]:
                switch_count += 1

        # Should have at least one switch, not too many
        return 1 <= switch_count <= len(vals) // 3

    def _find_trigger_column(self, rows: List[Dict], target_col: str) -> str:
        """Find which input column triggers state changes."""
        if not rows or target_col not in rows[0]:
            return ""

        for col in self._input_column_names:
            vals = [r.get(col) for r in rows]
            if any(v is not None for v in vals):
                # Check if this correlates with segment changes
                segment_vals = [r.get(target_col) for r in rows]
                for i in range(1, len(segment_vals)):
                    if segment_vals[i] != segment_vals[i-1] and vals[i] is not None and vals[i-1] is not None:
                        if vals[i] != vals[i-1]:
                            return col
        return self._input_column_names[0] if self._input_column_names else "value"


