    WINDOW_AVG = "window_avg"
    WINDOW_COUNT = "window_count"
    SEGMENT_ID = "segment_id"
    PHASE_FLAG = "phase_flag"


class TransformState:
    """
    Serializable state for streaming transforms.

    This holds all the state needed to correctly process data streams,
    supporting both lookbehind windows and lookahead for neighbor filtering.
    """

    def __init__(self):
        self.prefix_sum: Dict[str, float] = defaultdict(float)
        self.prefix_count: Dict[str, int] = defaultdict(int)
        self.windows: Dict[str, Deque] = {}  # {transform_key: deque of values}
        self.state_vars: Dict[str, Any] = {}
        self.deferred_row: Optional[Dict] = None  # Row waiting for lookahead
        self.deferred_idx: int = -1  # Index of deferred row
        self.window_sizes: Dict[str, int] = {}
        self.processed_count: int = 0
        self.active_lookbehind: bool = False
        self.lookahead_buffer: List[Dict] = []  # For lookahead of 1 row

    def to_dict(self) -> Dict:
        """Serialize state to a dictionary."""
        return {
            "prefix_sum": dict(self.prefix_sum),
            "prefix_count": dict(self.prefix_count),
            "windows": {k: list(v) for k, v in self.windows.items()},
            "state_vars": dict(self.state_vars),
            "deferred_row": self.deferred_row,
            "deferred_idx": self.deferred_idx,
            "window_sizes": dict(self.window_sizes),
            "processed_count": self.processed_count,
            "active_lookbehind": self.active_lookbehind,
            "lookahead_buffer": self.lookahead_buffer if self.lookahead_buffer else []
        }

    @classmethod
    def from_dict(cls, data: Dict) -> 'TransformState':
        """Deserialize state from a dictionary."""
        state = cls()
        state.prefix_sum = defaultdict(float, data.get("prefix_sum", {}))
        state.prefix_count = defaultdict(int, data.get("prefix_count", {}))
        state.windows = {k: deque(v) for k, v in data.get("windows", {}).items()}
        state.state_vars = data.get("state_vars", {})
        state.deferred_row = data.get("deferred_row")
        state.deferred_idx = data.get("deferred_idx", -1)
        state.window_sizes = data.get("window_sizes", {})
        state.processed_count = data.get("processed_count", 0)
        state.active_lookbehind = data.get("active_lookbehind", False)
        state.lookahead_buffer = data.get("lookahead_buffer", [])
        return state

    def clear(self):
        """Reset all state."""
        self.prefix_sum.clear()
        self.prefix_count.clear()
        self.windows.clear()
        self.state_vars.clear()
        self.deferred_row = None
        self.deferred_idx = -1
        self.window_sizes.clear()
        self.processed_count = 0
        self.active_lookbehind = False
        self.lookahead_buffer = []


class BaseParser:
    """Base class for file parsers."""

    def parse(self):
        raise NotImplementedError


class CSVParser(BaseParser):
    def __init__(self, path: Path):
        self.path = path

    def parse(self):
        with open(self.path, "r", encoding="utf-8") as f:
            reader = csv.DictReader(f)
            for row in reader:
                yield {k: cls._convert(v) for k, v in row.items()}

    @staticmethod
    def _convert(v: str) -> Any:
        if not v:
            return v
        if v.lower() == "true":
            return True
        if v.lower() == "false":
            return False
        try:
            return int(v)
        except ValueError:
            pass
        try:
            return float(v)
        except ValueError:
            pass
        return v


class TSVParser(CSVParser):
    def parse(self):
        with open(self.path, "r", encoding="utf-8") as f:
            reader = csv.DictReader(f, delimiter="\\t")
            for row in reader:
                yield {k: self._convert(v) for k, v in row.items()}


class JSONLParser(BaseParser):
    def __init__(self, path: Path):
        self.path = path

    def parse(self):
        with open(self.path, "r", encoding="utf-8") as f:
            for line in f:
                line = line.strip()
                if line:
                    yield json.loads(line)


class JSONParser(BaseParser):
    def __init__(self, path: Path):
        self.path = path

    def parse(self):
        with open(self.path, "r", encoding="utf-8") as f:
            data = json.load(f)
        if isinstance(data, list):
            for item in data:
                yield item


