class DynamicPreprocessor:
    """
    Dynamic preprocessor that applies inferred transformations to streaming data.

    Args:
        buffer: Maximum number of rows to keep in memory at once
        cache_dir: Optional directory for caching processed rows and state
    """

    def __init__(self, buffer: int, cache_dir: Optional[str] = None):
        self.buffer = buffer
        self.cache_dir = Path(cache_dir) if cache_dir else None
        self._parser_map = {
            "csv": CSVParser,
            "tsv": TSVParser,
            "jsonl": JSONLParser,
            "json": JSONParser,
        }
        self._extension = "{{extension}}"
        self._state = TransformState()
        self._row_counter = 0
        self._cache_file: Optional[Path] = None

    def __call__(self, path: str) -> Iterator[Dict[str, Any]]:
        """Process a data file and yield transformed rows."""
        return self._process(Path(path))

    def _process(self, path: Path) -> Iterator[Dict[str, Any]]:
        """Process a file with optional caching."""
        parser_class = self._parser_map[self._extension]
        parser = parser_class(path)

        if self.cache_dir is None:
            yield from self._process_direct(parser, path)
        else:
            yield from self._process_with_cache(parser, path)

    def _process_direct(self, parser, path: Path) -> Iterator[Dict[str, Any]]:
        """Process without caching, using streaming state."""
        buffer = []
        self._state.clear()
        self._row_counter = 0

        for row in parser.parse():
            row_idx = self._row_counter
            self._row_counter += 1

            # Handle lookahead if needed for neighbor filtering
            should_process = self._process_filter(row_idx, row)

            if should_process:
                self._state.lookahead_buffer.append({"row": row, "idx": row_idx})

            # When we have enough rows in lookahead buffer, or at end, emit them
            if len(self._state.lookahead_buffer) >= 2 or (self._row_counter >= self._get_total_rows_estimate(parser) and self._state.lookahead_buffer):
                # Process buffered rows
                for buffered in self._state.lookahead_buffer[:-1] if self._state.active_lookbehind else self._state.lookahead_buffer:
                    transformed = self._transform_with_state(row_idx, buffered["row"])
                    if transformed is not None:
                        buffer.append(transformed)

                        if len(buffer) >= self.buffer:
                            for item in buffer:
                                yield item
                            buffer.clear()
                self._state.lookahead_buffer = self._state.lookahead_buffer[-1:] if self._state.active_lookbehind else []

        # Flush remaining
