class TransformationInferrer:
    """Infer transformations from input/output sample pairs."""

    def __init__(self, input_rows: List[Dict], output_rows: List[Dict], ext: str):
        self.input_rows = input_rows
        self.output_rows = output_rows
        self.extension = ext
        self.filter_predicates: List[Tuple[int, bool]] = []
        self.output_columns: Set[str] = set()
        self.column_transforms: Dict[str, Dict] = {}  # Simple transforms
        self._stateful_transforms: Dict[str, Dict] = {}  # Stateful transforms
        self._input_column_names: List[str] = []
        self._filter_type: Optional[str] = None
        self._filter_info: Dict = {}
        self._infer()

    def _infer(self):
        """Infer all transformations."""
        if self.input_rows:
            self._input_column_names = list(self.input_rows[0].keys())

        for row in self.output_rows:
            self.output_columns.update(row.keys())

        self._match_rows()
        self._infer_filter()
        self._infer_transforms()

    def _match_rows(self):
        """Match output rows to input rows, handling stateful columns."""
        input_by_tuple = {}
        for i, row in enumerate(self.input_rows):
            key = tuple(sorted(row.items()))
            if key not in input_by_tuple:
                input_by_tuple[key] = []
            input_by_tuple[key].append(i)

        kept_mask = [None] * len(self.input_rows)
        used_indices = set()

        for out_row in self.output_rows:
            out_key = tuple(sorted(out_row.items()))
            found = False

            # Direct match
            for key, indices in input_by_tuple.items():
                if key == out_key:
                    for idx in indices:
                        if idx not in used_indices:
                            kept_mask[idx] = True
                            used_indices.add(idx)
                            found = True
                            break
                if found:
                    break

            # Partial match for transformed columns
            if not found:
                best_score = 0
                best_idx = -1
                for i, in_row in enumerate(self.input_rows):
                    if i in used_indices:
                        continue
                    match_score = 0
                    for k in out_row.keys():
                        if k in in_row and self._values_compatible(in_row[k], out_row[k]):
                            match_score += 1
                    if match_score > best_score:
                        best_score = match_score
                        best_idx = i
                if best_score > 0:
                    kept_mask[best_idx] = True
                    used_indices.add(best_idx)

        for i, kept in enumerate(kept_mask):
            if kept is None:
                kept_mask[i] = False

        self.filter_predicates = [(i, bool(kept)) for i, kept in enumerate(kept_mask)]

    def _values_compatible(self, val1: Any, val2: Any) -> bool:
        if val1 == val2:
            return True
        if isinstance(val1, (int, float)) and isinstance(val2, (int, float)):
            return abs(val1 - val2) < 1e-10
        if isinstance(val1, str) and isinstance(val2, str):
            return val1 == val2
        try:
            n1 = float(val1) if not isinstance(val1, bool) else None
            n2 = float(val2) if not isinstance(val2, bool) else None
            if n1 is not None and n2 is not None:
                return abs(n1 - n2) < 1e-10
        except (ValueError, TypeError):
            pass
        return False

    def _infer_filter(self):
        """Infer filter predicates, including neighbor-based."""
        kept_rows = [self.input_rows[i] for i, kept in self.filter_predicates if kept]
        dropped_rows = [self.input_rows[i] for i, kept in self.filter_predicates if not kept]
        kept_indices = set(i for i, kept in self.filter_predicates if kept)
        dropped_indices = [i for i, kept in self.filter_predicates if not kept]

        if not dropped_indices:
            self._filter_type = "none"
            self._filter_info = {}
            return

        # Try neighbor patterns first
        neighbor_info = self._infer_neighbor_filter(kept_indices, dropped_indices)
        if neighbor_info:
            self._filter_type = "neighbor"
            self._filter_info = neighbor_info
            return

        # Fallback to column-based
        col_filters = self._infer_column_filter(kept_rows, dropped_rows)
        if col_filters:
            self._filter_type = "column"
            self._filter_info = col_filters
            return

        self._filter_type = "index"
        self._filter_info = {"dropped": dropped_indices}

    def _infer_neighbor_filter(self, kept_indices: Set[int], dropped_indices: List[int]) -> Optional[Dict]:
        if not self.input_rows:
            return None

        # Check for "keep first of consecutive duplicates"
        first_col = self._input_column_names[0] if self._input_column_names else "value"
        consecutive_groups = []
        current = []

        for i, row in enumerate(self.input_rows):
            val = row.get(first_col)
            if current and val == self.input_rows[current[0]].get(first_col):
                current.append(i)
            else:
                if current:
                    consecutive_groups.append(current)
                current = [i]
        if current:
            consecutive_groups.append(current)

        for group in consecutive_groups:
            first = group[0]
            rest = group[1:]
            if first in kept_indices and all(idx not in kept_indices for idx in rest):
                return {
                    "pattern": "keep_first_of_duplicates",
                    "field": first_col
                }

        # Check for "drop row if next row has status='duplicate'"
        if "status" in self.input_rows[0]:
            # Check if any row is dropped when next row has status='duplicate'
            matches = 0
            total = 0
            for i in range(len(self.input_rows) - 1):
                if self.input_rows[i+1].get("status") == "duplicate":
                    total += 1
                    if i not in kept_indices:
                        matches += 1
            if total > 0 and matches >= total * 0.5:
                return {
                    "pattern": "drop_if_next_duplicate",
                    "field": "status"
                }

        return None

    def _infer_column_filter(self, kept_rows: List[Dict], dropped_rows: List[Dict]) -> Optional[Dict]:
        if not kept_rows or not dropped_rows:
            return None

        filters = []
        for col in self._input_column_names:
            kept_vals = [r.get(col) for r in kept_rows if col in r]
            dropped_vals = [r.get(col) for r in dropped_rows if col in r]

            if not kept_vals or not dropped_vals:
                continue

            if len(set(kept_vals)) == 1:
                val = kept_vals[0]
                if not any(dv == val for dv in dropped_vals if dv is not None):
                    filters.append(("eq", col, val))

            if len(set(dropped_vals)) == 1:
                val = dropped_vals[0]
                if not any(kv == val for kv in kept_vals if kv is not None):
                    filters.append(("ne", col, val))

            if all(isinstance(v, (int, float)) for v in kept_vals + dropped_vals):
                max_dropped = max(v for v in dropped_vals if v is not None)
                min_kept = min(v for v in kept_vals if v is not None)
                if min_kept > max_dropped:
                    filters.append(("gt", col, max_dropped))

        return {"filters": filters} if filters else None

    def _infer_transforms(self):
        """Infer all column transformations, including stateful."""
        kept_input_rows = [r for kept, r in zip([p[1] for p in self.filter_predicates], self.input_rows) if kept]

        for out_col in self.output_columns:
            # Check if it's a stateful transform first
            stateful = self._try_infer_stateful(out_col, kept_input_rows)
            if stateful:
                self._stateful_transforms[out_col] = stateful
            else:
                # Simple transform
                simple = self._infer_simple_transform(out_col, kept_input_rows)
                self.column_transforms[out_col] = simple

    def _try_infer_stateful(self, col: str, kept_rows: List[Dict]) -> Optional[Dict]:
        """Try to infer a stateful transform for a column."""
        if col not in kept_rows[0] if kept_rows else False:
            return None

        # Get the corresponding input column
        if self._input_column_names:
            source = self._input_column_names[0] if self._input_column_names in kept_rows[0] else self._input_column_names[0] if len(kept_rows[0]) > 0 else col
        else:
            source = col

        in_vals = [r.get(source) for r in kept_rows if source in r]
        out_vals = [r.get(col) for r in kept_rows if col in r]

        if len(in_vals) < 2:
            return None

        # Check prefix sum
        prefix = self._check_prefix_transform(in_vals, out_vals)
        if prefix:
            return {"type": "stateful", "kind": "prefix", "source": source, "params": prefix}

        # Check sliding window
        window = self._check_sliding_window(in_vals, out_vals)
        if window:
            return {"type": "stateful", "kind": "window", "source": source, "params": window}

        # Check state machine (segment_id, phase)
        sm = self._check_state_machine(col, kept_rows)
        if sm:
            return {"type": "stateful", "kind": "state_machine", "source": source, "params": sm}

        return None

    def _check_prefix_transform(self, in_vals: List, out_vals: List) -> Optional[Dict]:
        pairs = [(iv, ov) for iv, ov in zip(in_vals, out_vals)
                 if isinstance(iv, (int, float)) and isinstance(ov, (int, float))]
        if len(pairs) < 2:
            return None

        # Check if out[i] = prefix_sum(in[0..i])
        running = 0
        results = []
        for iv, ov in pairs:
            running += iv
            results.append((running, ov))

        # Check for linear relationship
        diffs = [(expected - actual) for expected, actual in results]
        if all(abs(d) < 1e-6 for d in diffs):
            return {"op": "sum", "coeff_a": 1.0, "coeff_b": 0.0}

        # Check for count
        count_results = [(i + 1, ov) for i, (_, ov) in enumerate(pairs)]
        count_diffs = [(expected - actual) for expected, actual in count_results]
        if all(abs(d) < 1e-6 for d in count_diffs):
            return {"op": "count", "coeff_a": 1.0, "coeff_b": 0.0}

        return None

    def _check_sliding_window(self, in_vals: List, out_vals: List) -> Optional[Dict]:
        pairs = [(iv, ov) for iv, ov in zip(in_vals, out_vals)
                 if isinstance(iv, (int, float)) and isinstance(ov, (int, float))]
        if len(pairs) < 2:
            return None

        for w in range(1, min(65, len(pairs) + 1)):
            if self._verify_window(pairs, w):
                return {"size": w, "op": self._get_window_op(pairs, w)}

        return None

    def _verify_window(self, pairs: List, window_size: int) -> bool:
        for i in range(window_size - 1, len(pairs)):
            window = [p[0] for p in pairs[i-window_size+1:i+1]]
            expected = sum(window)  # Default check for sum
            if abs(expected - pairs[i][1]) > 1e-6:
                # Check for average
                expected_avg = sum(window) / len(window)
                if abs(expected_avg - pairs[i][1]) > 1e-6:
                    return False
        return True

    def _get_window_op(self, pairs: List, window_size: int) -> str:
        window = [p[0] for p in pairs[:window_size]]
        expected_sum = sum(window)
        if abs(expected_sum - pairs[window_size-1][1]) < 1e-6:
            return "sum"
        return "avg"

    def _check_state_machine(self, col: str, rows: List[Dict]) -> Optional[Dict]:
        vals = [r.get(col) for r in rows]
        if not vals:
            return None

        try:
            int_vals = [int(v) if v is not None else -1 for v in vals]
        except (ValueError, TypeError):
            return None

        # Check for segment ID pattern
        changes = 0
        for i in range(1, len(int_vals)):
            if int_vals[i] < int_vals[i-1]:
                return None  # Should not decrease for segment
            if int_vals[i] > int_vals[i-1]:
                if int_vals[i] - int_vals[i-1] > 1:
                    return None
                changes += 1

        if changes > 0:
            return {"kind": "segment_id"}
        return None

    def _infer_simple_transform(self, out_col: str, kept_rows: List[Dict]) -> Dict:
        """Infer a simple (non-stateful) transform."""
        if not kept_rows:
            return {"type": "constant", "value": None}

        # Constant check
        vals = [r.get(out_col) for r in kept_rows if out_col in r]
        if len(set(vals)) == 1:
            return {"type": "constant", "value": vals[0]}

        # Copy check
        if self._input_column_names and out_col in kept_rows[0]:
            return {"type": "copy", "source": out_col}

        # Numeric linear
        pairs = [(r.get(out_col), r.get(self._input_column_names[0]))
                 for r in kept_rows
                 if out_col in r and self._input_column_names[0] in r]
        numeric_pairs = [(in_v, out_v) for out_v, in_v in pairs
                         if isinstance(in_v, (int, float)) and isinstance(out_v, (int, float))]
        if len(numeric_pairs) >= 2:
            x1, y1 = numeric_pairs[0]
            x2, y2 = numeric_pairs[1]
            if x2 != x1:
                a = (y2 - y1) / (x2 - x1)
                b = y1 - a * x1
                if all(abs(a * x + b - y) < 1e-6 for x, y in numeric_pairs):
                    return {"type": "numeric", "op": "linear", "a": a, "b": b}

        # Fallback to copy or drop
        if any(out_col in r for r in kept_rows):
            return {"type": "copy", "source": out_col}
        return {"type": "dropped"}

